css:
/* =========================
   PAGE SETTINGS
========================= */

@page {
    size: A4;
    margin: 8mm;
}

.print-format {
    width: 100% !important;
    max-width: 100% !important;
    padding: 0 !important;
    margin: 0 !important;
}

.service-invoice {
    width: 100%;
    font-family: Arial, Helvetica, sans-serif;
    font-size: 12px;
    color: #000;
    line-height: 1.35;
}

/* =========================
   HEADER
========================= */

.header-section {
    width: 100%;
    display: table;
    margin-bottom: 12px;
}

.company-left,
.company-center,
.invoice-title {
    display: table-cell;
    vertical-align: top;
}

.company-left {
    width: 12%;
}

.company-center {
    width: 58%;
    padding-left: 10px;
}

.invoice-title {
    width: 30%;
    text-align: right;
}

.logo {
    max-height: 90px;
    max-width: 90px;
}

.company-center h2 {
    margin: 0;
    padding: 0;
    font-size: 20px;
    font-weight: 700;
}

.company-center div {
    font-size: 13px;
    margin-top: 2px;
}

.invoice-title h3 {
    margin: 0;
    font-size: 20px;
    font-weight: bold;
}

/* =========================
   INVOICE DETAILS
========================= */

.invoice-info {
    width: 100%;
    margin-bottom: 8px;
    border-collapse: collapse;
}

.invoice-info td {
    padding: 2px 4px;
    font-size: 12px;
}

/* =========================
   TABLES
========================= */

.main-table,
.party-table,
.items-table,
.tax-table,
.gst-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 6px;
}

.main-table td,
.party-table td,
.items-table th,
.items-table td,
.tax-table td,
.gst-table th,
.gst-table td {
    border: 1px solid #000;
    padding: 4px 5px;
    vertical-align: top;
}

/* =========================
   PARTY TABLE
========================= */

.party-table td {
    font-size: 12px;
}

/* =========================
   ITEM TABLE
========================= */

.items-table th,
.gst-table th {
    background: #f2f2f2;
    font-weight: bold;
    text-align: left;
}

.items-table td,
.gst-table td {
    font-size: 12px;
}

.text-right {
    text-align: right;
}

.text-center {
    text-align: center;
}

/* =========================
   TOTALS
========================= */

.grand-total td,
.grand-total {
    font-weight: bold;
    font-size: 13px;
}

/* =========================
   AMOUNT IN WORDS
========================= */

.amount-words {
    margin-top: 10px;
    margin-bottom: 12px;
    font-size: 13px;
    font-weight: bold;
    border-top: 1px solid #000;
    border-bottom: 1px solid #000;
    padding: 6px 0;
}

/* =========================
   SECTION TITLES
========================= */

.section-title {
    margin-top: 12px;
    margin-bottom: 5px;
    font-size: 14px;
    font-weight: bold;
}

/* =========================
   GST TABLE
========================= */

.gst-table th {
    text-align: center;
}

.gst-table td {
    text-align: right;
}

.gst-table td:first-child {
    text-align: left;
}

/* =========================
   FOOTER SIGNATURES
========================= */

.signature-section {
    width: 100%;
    margin-top: 80px;
    display: table;
}

.signature-section div {
    display: table-cell;
    width: 33.33%;
    text-align: center;
    vertical-align: bottom;
}

.signature-section div::before {
    content: "";
    display: block;
    border-top: 1px solid #000;
    width: 70%;
    margin: 0 auto 5px auto;
}

/* =========================
   PRINT FOOTER
========================= */

.print-footer {
    margin-top: 100px;
    width: 100%;
    font-size: 11px;
}

.print-footer table {
    width: 100%;
}

.print-footer td:first-child {
    text-align: left;
}

.print-footer td:last-child {
    text-align: right;
}

/* =========================
   PREVENT PAGE BREAKS
========================= */

.items-table,
.tax-table,
.gst-table,
.party-table {
    page-break-inside: avoid;
}

tr {
    page-break-inside: avoid;
}
